SELECT count(*) FROM title, movie_companies, movie_keyword, company_type, company_name, keyword, kind_type, movie_info, info_type WHERE movie_companies.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id AND movie_keyword.keyword_id = keyword.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id;